solutions.python:
import sys

class Solution:
    def solve(self, s, substr)
        :
        count = 0
        for i in range(len(s) - len(substr) + 1):
            if s[i:i+len(substr)] == substr:
                count++
        return str(count)

t = Solution()
print(t.solve(sys.stdin.readline().strip(), sys.stdin.readline().strip()))

