#include <sstream>
#include <string>
using namespace std;

int main() {
  string s, substr;
  cin >> s >> substr;
  string solve(string s, string substr) {
    int count = 0;
    for(int i = 0; i <= s.length(); i++) {
      if(i + substr.length() <= s.length() && s.substr(i, substr.length()) == substr) {
        count++;
      }
    }
    return to_string(count);
  }
  cout << solve(s, substr) << endl;
